import { PanelCard } from './PanelCard'

type TaskPanelProps = {
  canStart: boolean
  canCancel: boolean
  isRunning: boolean
  isCancelling: boolean
  total: number
  completed: number
  failed: number
  currentFileName?: string
  currentStage?: string
  onStart: () => void
  onCancel: () => void
}

export function TaskPanel(props: TaskPanelProps) {
  const progress = props.total > 0 ? Math.round(((props.completed + props.failed) / props.total) * 100) : 0

  return (
    <PanelCard title="任务控制">
      <div style={styles.container}>
        <div style={styles.actions}>
          <button onClick={props.onStart} disabled={!props.canStart}>
            {props.isRunning ? '处理中...' : '开始处理'}
          </button>
          <button onClick={props.onCancel} disabled={!props.canCancel}>
            {props.isCancelling ? '取消中...' : '取消任务'}
          </button>
        </div>

        <div style={styles.stats}>
          <div>总数：{props.total}</div>
          <div>完成：{props.completed}</div>
          <div>失败：{props.failed}</div>
          <div>进度：{progress}%</div>
        </div>

        <div style={styles.current}>当前文件：{props.currentFileName || '无'}</div>
        <div style={styles.current}>当前阶段：{props.currentStage || '无'}</div>
      </div>
    </PanelCard>
  )
}

const styles: Record<string, React.CSSProperties> = {
  container: {
    display: 'flex',
    flexDirection: 'column',
    gap: '12px',
  },
  actions: {
    display: 'flex',
    gap: '8px',
  },
  stats: {
    display: 'grid',
    gridTemplateColumns: 'repeat(2, minmax(0, 1fr))',
    gap: '8px',
    fontSize: '13px',
  },
  current: {
    fontSize: '13px',
    color: '#374151',
    background: '#f9fafb',
    border: '1px solid #e5e7eb',
    borderRadius: '8px',
    padding: '10px 12px',
    wordBreak: 'break-all',
  },
}
